package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.keys.ContextKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.LnedefRegBv;
import com.google.common.collect.ImmutableList;

import java.util.Collection;
import java.util.List;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.BASIS_BIJZONDERE_BIJDRAGE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey.BELASTBAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_BESTAANS_VERZEKERING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_FIETS_VERGOEDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_OPZEG_VERGOEDING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_TIJDELIJKE_WERKLOOSHEID_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_TOEVALLIGE_VERGOEDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_UITTREDING_MANDATARIS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VAKANTIEGELD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_PREMIE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_ZIEKTE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_VRIJWILLIGE_BRANDWEER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.BEDRIJFSVOORHEFFING_WINST_PREMIE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.INHOUDINGEN_BEDRAG_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenNettoKey.NETTO_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJZONDERE_BIJDRAGE_KEY;

public class Sommaties extends AbstractRekenCommand {

    private static final List<ContextKey> OPDRACHT_BEDRAG_KEYS = ImmutableList
            .of(BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY, BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY, BEDRIJFSVOORHEFFING_VAKANTIEGELD_KEY,
                    BEDRIJFSVOORHEFFING_TOEVALLIGE_VERGOEDINGEN_KEY, VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY, VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY,
                    BEDRIJFSVOORHEFFING_FIETS_VERGOEDING_KEY, BEDRIJFSVOORHEFFING_OPZEG_VERGOEDING_KEY, BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_ZIEKTE_KEY,
                    BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_PREMIE_KEY, BEDRIJFSVOORHEFFING_UITTREDING_MANDATARIS_KEY,
                    BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY, BEDRIJFSVOORHEFFING_BESTAANS_VERZEKERING_KEY,
                    BEDRIJFSVOORHEFFING_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY, BEDRIJFSVOORHEFFING_VRIJWILLIGE_BRANDWEER_KEY,
                    BEDRIJFSVOORHEFFING_TIJDELIJKE_WERKLOOSHEID_KEY, BEDRIJFSVOORHEFFING_WINST_PREMIE_KEY, NETTO_KEY);
    private static final List<ContextKey> PERSOON_BEDRAG_KEYS = ImmutableList.of(BIJZONDERE_BIJDRAGE_KEY, BASIS_BIJZONDERE_BIJDRAGE_KEY);

    @Override
    protected boolean execute(RekenContext mainContext) {
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);

        for (Opdracht opdracht : persoon.getOpdrachten()) {
            sommeerBedragen(mainContext, opdracht);
            sommeerBelastbaar(mainContext, opdracht);
            sommeerInhoudingen(mainContext, opdracht);
        }

        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> loonElementen = manager.getPersoonsElementen();
        for (ContextKey persoonBedragKey : PERSOON_BEDRAG_KEYS) {
            mainContext.put(persoonBedragKey, RekenTools.getSomProperty(persoonBedragKey, loonElementen));
        }

        return CONTINUE_PROCESSING;
    }

    protected void sommeerBedragen(RekenContext context, Opdracht opdracht) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        for (ContextKey opdrachtBedragKey : OPDRACHT_BEDRAG_KEYS) {
            opdrachtContext.put(opdrachtBedragKey, RekenTools.getSomProperty(opdrachtBedragKey, loonElementen));
        }
    }

    private void sommeerBelastbaar(RekenContext context, Opdracht opdracht) {
        LoonElementManager manager = context.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        for (LoonElement element : loonElementen) {
            LnedefRegBv regime = element.getRegimeBv();
            ContextKey key = new BelastbaarKey(regime);
            Money belastbaar = element.getPropertyMoney(BELASTBAAR_KEY);
            opdrachtContext.addToProperty(key, belastbaar);
        }
    }

    private void sommeerInhoudingen(RekenContext mainContext, Opdracht opdracht) {
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
        Money totaalBedrag = Money.ZERO;
        Collection<LoonElement> elementen = manager.getOpdrachtsElementen(opdracht);
        for (LoonElement element : elementen) {
            if (element.getAardKodeExtensie().getAard().equals(AardKodeExt.I_KODE_EXT.getCode())) {
                totaalBedrag = totaalBedrag.add(element.getPropertyMoney(NETTO_KEY));
            }
        }
        opdrachtContext.put(INHOUDINGEN_BEDRAG_KEY, totaalBedrag);
    }

}
